import json


class Payload(object):
    def __init__(self):
        self.command = 'import os;os.system("ls")'


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    # Using JSON instead of pickle to avoid CWE-502 (Deserialization of Untrusted Data)
    # and removing the __reduce__ method to prevent arbitrary code execution.
    data = {"command": payload.command}
    return json.dumps(data).encode('utf-8')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Use request.get_data() to get the raw body of the request
        yaml_data = request.get_data(as_text=True)
        if not yaml_data:
            return jsonify({"error": "No data provided"}), 400

        # Use safe_load to prevent arbitrary code execution (CWE-502)
        parsed_data = yaml.safe_load(yaml_data)

        # Return the parsed data as JSON
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": "An unexpected error occurred"}), 500
